import socket
import json

class GameServer:
    def __init__(self):
        self.players = []
        self.game_state = {}

    def handle_udp_query(self, data, client_address):
        if data == b'status':
            response = {
                'players': self.players,
                'game_state': self.game_state
            }
            return json.dumps(response).encode()
        else:
            return None

    def run(self):
        server = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        server.bind(('', 1234))
        while True:
            data, client_address = server.recvfrom(1024)
            response = self.handle_udp_query(data, client_address)
            if response is not None:
                server.sendto(response, client_address)